import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ executionId }) {
  const ex = await execution(executionId);
  const event = ex.params.event;

  // Fetch full problem details
  const problemResp = await fetch('/api/v2/problems/' + event['event.id']);
  const problem = await problemResp.json();

  // Build analysis time window: problem start -5 min to +15 min
  const startMs = problem.startTime;
  const fromMs = startMs - 5 * 60 * 1000;
  const toMs = startMs + 15 * 60 * 1000;
  const from = new Date(fromMs).toISOString();
  const to = new Date(toMs).toISOString();

  // --- Determine the SQL Server instance name ---
  // Strategy 1: Extract from the affected entity name (e.g., "SQLSERVER01\PROD")
  // Strategy 2: Fall back to the entity display name
  let sqlInstance = 'unknown';
  const affectedEntities = problem.affectedEntities || [];
  const rootCauseEntity = problem.rootCauseEntity || {};

  // Prefer root cause entity if it looks like a database
  const primaryEntity = rootCauseEntity.entityId
    ? rootCauseEntity
    : affectedEntities[0] || {};

  if (primaryEntity.name) {
    sqlInstance = primaryEntity.name;
  }

  // If the entity is a service, try to find a related database entity
  // by checking impacted entities for a CUSTOM_DEVICE or HOST type
  for (const entity of affectedEntities) {
    const name = entity.name || '';
    // SQL Server instance names typically contain a backslash or look like hostnames
    if (name.includes('\\') || name.toUpperCase().includes('SQL')) {
      sqlInstance = name;
      break;
    }
  }

  return {
    problemId: problem.problemId,
    displayId: problem.displayId,
    title: problem.title,
    status: problem.status,
    entityId: primaryEntity.entityId?.id || 'unknown',
    entityName: primaryEntity.name || 'unknown',
    sqlInstance: sqlInstance,
    from: from,
    to: to,
    startTime: new Date(startMs).toISOString()
  };
}

import { execution } from '@dynatrace-sdk/automation-utils';
import { queryExecutionClient } from '@dynatrace-sdk/client-query';

export default async function ({ executionId }) {
  const ex = await execution(executionId);
  const ctx = ex.result('extract_problem_context');

  // Step 1: Detect SQL Server version from server_config
  const versionQuery = `
    fetch logs
    | filter dt.extension.name == "custom:mssql.sp.diagnostics"
    | filter event.group == "server_config"
    | filter config_name == "ProductMajorVersion"
    | filter sql_server_instance == "${ctx.sqlInstance}"
    | sort timestamp desc | limit 1
  `;

  let majorVersion = 0;
  try {
    const versionResult = await queryExecutionClient.queryExecute({ body: { query: versionQuery } });
    if (versionResult.result?.records?.length > 0) {
      majorVersion = parseInt(versionResult.result.records[0].configured_value) || 0;
    }
  } catch (e) {
    // Version detection failed — fall back to no-plan analysis
  }

  let planData = [];
  let layer3Method = 'unavailable';

  if (majorVersion >= 15) {
    // SQL Server 2019+ — retrieve actual plans via dm_exec_query_plan_stats DMV
    layer3Method = 'dm_exec_query_plan_stats (zero overhead)';
    const planQuery = `
      fetch logs
      | filter event.group == "actual_execution_plans"
      | filter sql_server_instance == "${ctx.sqlInstance}"
      | filter timestamp >= toTimestamp("${ctx.from}")
          AND timestamp <= toTimestamp("${ctx.to}")
      | sort avg_elapsed_us desc
      | limit 10
    `;
    try {
      const planResult = await queryExecutionClient.queryExecute({ body: { query: planQuery } });
      planData = planResult.result?.records || [];
    } catch (e) {
      // Plan retrieval failed
    }
  } else if (majorVersion >= 13) {
    // SQL Server 2016 SP1+ / 2017 — XEvent fallback
    layer3Method = 'XEvent query_thread_profile (lightweight, ~2% overhead)';
  } else if (majorVersion > 0) {
    // Pre-2016 — limited deep capture
    layer3Method = 'XEvent standard (higher overhead, time-bounded)';
  } else {
    layer3Method = 'Version detection failed — Layer 3 not available';
  }

  return {
    majorVersion: majorVersion,
    layer3Method: layer3Method,
    actualPlansAvailable: planData.length > 0,
    planData: planData
  };
}

